// ============ HELPER: Escape HTML (protege contra XSS) ============
function escapeHTML(str) {
  if (str === null || str === undefined) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

// ============ MATRIZ DE RISCO PARA PDF (modo claro) ============
function construirMatrizHTMLClara(riscosFiltrados) {
  const mapaNiveis = {};
  for (let p = 1; p <= 5; p++) {
    for (let i = 1; i <= 5; i++) {
      mapaNiveis[nivelMatriz(p, i)] = { prob: p, imp: i };
    }
  }

  const porCelula = {};
  const ordenados = riscosFiltrados.slice().sort(function(a, b) {
    return (b.prob * b.imp) - (a.prob * a.imp);
  });

  ordenados.forEach(function(r) {
    const nivel = r.prob * r.imp;
    const residual = nivel * r.nivelControle;
    let ri = Math.max(1, Math.min(25, Math.round(residual)));
    const coord = mapaNiveis[ri];
    if (!coord) return;
    const ch = coord.prob + "-" + coord.imp;
    if (!porCelula[ch]) porCelula[ch] = [];
    porCelula[ch].push(obterNumeroRisco(r.id));
  });

  const yLabels = ["Muito Alto", "Alto", "Médio", "Baixo", "Muito Baixo"];
  const xLabels = ["Raro", "Pouco Prov.", "Provável", "Muito Prov.", "Quase Certo"];

  let html = '<div style="display:grid;grid-template-columns:110px repeat(5,1fr);gap:4px;">';

  // Célula vazia (canto superior esquerdo)
  html += '<div></div>';

  // Header das colunas (Probabilidade)
  for (let p = 1; p <= 5; p++) {
    html += '<div style="background:#f5f8fa;border:1px solid #d4dde3;padding:8px 4px;border-radius:4px;text-align:center;font-size:13px;font-weight:700;color:#1a2b3d;">' + xLabels[p-1] + '</div>';
  }

  // Linhas (Impacto de cima pra baixo = 5 até 1)
  for (let i = 5; i >= 1; i--) {
    // Label do impacto
    html += '<div style="background:#f5f8fa;border:1px solid #d4dde3;padding:6px 4px;border-radius:4px;text-align:center;font-size:13px;font-weight:700;color:#1a2b3d;display:flex;align-items:center;justify-content:center;">' + yLabels[5-i] + '</div>';

    // Células da linha
    for (let p = 1; p <= 5; p++) {
      const nv = nivelMatriz(p, i);
      let cor = "#3ad48a";  // Baixo (verde)
      if (nv >= 20) cor = "#e05a5a";      // Alto (vermelho)
      else if (nv >= 7) cor = "#f5c94a";  // Médio (amarelo)

      const ch = p + "-" + i;
      const chips = porCelula[ch] || [];

      html += '<div style="background:' + cor + ';padding:8px 4px;border-radius:4px;text-align:center;color:#1a2b3d;font-weight:700;min-height:55px;display:flex;flex-direction:column;justify-content:center;">' +
        '<span style="font-size:13px;opacity:0.7;">' + nv + '</span>';

      if (chips.length > 0) {
        html += '<div style="display:flex;flex-wrap:wrap;gap:2px;justify-content:center;margin-top:4px;">';
        chips.forEach(function(c) {
          html += '<span style="display:inline-block;background:#1a2b3d;color:#ffffff;padding:2px 6px;border-radius:6px;font-size:12px;font-weight:700;">' + c + '</span>';
        });
        html += '</div>';
      }
      html += '</div>';
    }
  }
  html += '</div>';

  // Label do eixo X
  html += '<div style="text-align:center;color:#0e9aa7;font-weight:700;font-size:11px;letter-spacing:2px;margin-top:10px;">→ PROBABILIDADE</div>';

  // Legenda
  html += '<div style="display:flex;gap:20px;justify-content:center;margin-top:12px;padding-top:10px;border-top:1px solid #d4dde3;font-size:11px;color:#1a2b3d;">' +
    '<span><span style="display:inline-block;width:14px;height:14px;background:#3ad48a;border-radius:3px;vertical-align:middle;margin-right:5px;"></span>Baixo (1-6)</span>' +
    '<span><span style="display:inline-block;width:14px;height:14px;background:#f5c94a;border-radius:3px;vertical-align:middle;margin-right:5px;"></span>Médio (7-19)</span>' +
    '<span><span style="display:inline-block;width:14px;height:14px;background:#e05a5a;border-radius:3px;vertical-align:middle;margin-right:5px;"></span>Alto (20-25)</span>' +
  '</div>';

  return html;
}

