// ============ VERIFICA SE PRECISA DE JUSTIFICATIVA ============
function verificarJustificativa() {
  const tratar = document.getElementById("rTratar").value;
  const prob = parseInt(document.getElementById("rProb").value) || 0;
  const imp  = parseInt(document.getElementById("rImp").value) || 0;
  const nivelControleEl = document.getElementById("rNivelControle");
  const nivelControle = nivelControleEl ? parseFloat(nivelControleEl.value) : 1;

  const nivel = prob * imp;
  const residual = nivel * nivelControle;

  const box = document.getElementById("justificativaBox");
  if (!box) return;

  // 🎯 Regra: Residual ≥ 19 + Tratar = "Não" → obriga justificativa
  if (residual >= 19 && tratar === "Não") {
    box.style.display = "block";
  } else {
    box.style.display = "none";
    // Limpa o campo se esconder
    const txt = document.getElementById("rJustificativa");
    if (txt) txt.value = "";
  }
}
