// ============ HELPER: Obter etapas de tratamento ============
function obterEtapasDash(risco) {
  if (!risco.tratamento) return [];

  // Formato novo: histórico
  if (Array.isArray(risco.tratamento.historico)) {
    return risco.tratamento.historico;
  }

  // Formato antigo: objeto único (compatibilidade)
  if (risco.tratamento.opcao || risco.tratamento.descricao) {
    return [risco.tratamento];
  }

  return [];
}

console.log("fecharModalRisco?", typeof fecharModalRisco);
console.log("fecharModal?", typeof fecharModal);
console.log("fecharModalNovoRisco?", typeof fecharModalNovoRisco);
function base64ParaFile(dataUrl, nome, tipo) {
  try {
    if (!dataUrl || !dataUrl.startsWith("data:")) {
      console.warn("[base64ParaFile] dataUrl inválido");
      return null;
    }
    const arr = dataUrl.split(",");
    const mime = tipo || (arr[0].match(/:(.*?);/) || [])[1] || "application/octet-stream";
    const bstr = atob(arr[1]);
    let n = bstr.length;
    const u8arr = new Uint8Array(n);
    while (n--) u8arr[n] = bstr.charCodeAt(n);
    return new File([u8arr], nome, { type: mime });
  } catch (e) {
    console.error("[base64ParaFile]", e);
    return null;
  }
}

function abrirModalRisco(id) {
  if (!processoAtualId) {
    showToast("Selecione um registro primeiro.", "error");
    tocarSom("error");
    return;
  }

  editandoId = (id !== undefined && id !== null && id !== "") ? id : null;

  const modal = document.getElementById("modalRisco");
  if (!modal) return;
  modal.style.display = "flex";

  const setVal = (elId, valor) => {
    const el = document.getElementById(elId);
    if (el) el.value = valor;
  };

  if (editandoId !== null) {
    // Editar risco existente
    const r = riscos.find(x => String(x.id) === String(editandoId));
    if (!r) return;

    const titulo = document.getElementById("modalTitle");
    if (titulo) titulo.innerHTML = '<i class="bi bi-pencil-square"></i> Editar Risco';

    setVal("riscoId", r.id);
    setVal("rEvento", r.evento || "");
    setVal("rFonte", r.causaFonte || "");
    setVal("rVulnerabilidade", r.causaVulnerabilidade || "");
    setVal("rConsequencia", r.consequencia || "");
    setVal("rProb", r.prob || "");
    setVal("rImp", r.imp || "");
    setVal("rDescControle", r.descControle || "");
    setVal("rNivelControle", r.nivelControle || 1);
    setVal("rTratar", r.tratar || "Não");
    setVal("rPrioritario", r.prioritario || "Não");
    setVal("rJustificativa", r.justificativaNaoTratar || "");
  } else {
    // Novo risco
    const titulo = document.getElementById("modalTitle");
    if (titulo) titulo.innerHTML = '<i class="bi bi-plus-circle"></i> Novo Risco';

    ["riscoId","rEvento","rFonte","rVulnerabilidade","rConsequencia",
     "rProb","rImp","rDescControle","rJustificativa"].forEach(id => setVal(id, ""));

    setVal("rNivelControle", "1");
    setVal("rTratar", "Não");
    setVal("rPrioritario", "Não");
  }

  // Atualiza preview do nível
  if (typeof calcularNivelPreview === "function") calcularNivelPreview();
  if (typeof verificarJustificativa === "function") verificarJustificativa();
}

function obterNivelFinalDashboard(risco){

    const prob =
        Number(risco.prob) || 1;

    const imp =
        Number(risco.imp) || 1;

    const controle =
        Number(risco.nivelControle) || 1;

    const residual =
        prob * imp * controle;

    if (
        String(risco.tratar || "")
            .toLowerCase() === "sim"
    ){

        const etapas =
            obterEtapasDash(risco);

        const etapa =
            etapas.length
                ? etapas[etapas.length - 1]
                : null;

        if (
            etapa &&
            etapa.nivelMonitoramento
        ){

            return (
                residual *
                Number(etapa.nivelMonitoramento)
            );

        }

    }

    return residual;
}

function obterPosicaoMatriz(nivel){

    nivel = Number(nivel) || 0;

    if (nivel >= 21)
        return { prob:5, imp:5 };

    if (nivel >= 16)
        return { prob:4, imp:5 };

    if (nivel >= 13)
        return { prob:4, imp:4 };

    if (nivel >= 10)
        return { prob:3, imp:4 };

    if (nivel >= 7)
        return { prob:3, imp:3 };

    if (nivel >= 5)
        return { prob:2, imp:3 };

    return { prob:1, imp:2 };

}

